const data = $input.first().json;
const symbols = data.symbols || [];

const tickerMap = {
  'S&P500': '^GSPC',
  'S&P 500': '^GSPC',
  'DAX': '^GDAXI'
};

return symbols.map(sym => {
  const resolvedSymbol = tickerMap[sym] || sym;
  return {
    json: {
      symbol: resolvedSymbol,
      displayName: sym,
      interval: data.interval || '1h',
      range: data.range || '5d'
    }
  };
});

const items = $input.all();
const parsedData = [];

for (const item of items) {
  const response = item.json;
  if (!response || !response.chart || !response.chart.result || !response.chart.result[0]) {
    continue;
  }

  const result = response.chart.result[0];
  const timestamps = result.timestamp || [];
  const quotes = (result.indicators && result.indicators.quote && result.indicators.quote[0]) || {};

  const opens = quotes.open || [];
  const highs = quotes.high || [];
  const lows = quotes.low || [];
  const closes = quotes.close || [];
  const volumes = quotes.volume || [];

  for (let i = 0; i < timestamps.length; i++) {
    if (timestamps[i] && closes[i] !== null && closes[i] !== undefined) {
      parsedData.push({
        symbol: result.meta.symbol || 'UNKNOWN',
        price_timestamp: new Date(timestamps[i] * 1000).toISOString(),
        open_price: opens[i] !== null ? opens[i] : null,
        high_price: highs[i] !== null ? highs[i] : null,
        low_price: lows[i] !== null ? lows[i] : null,
        close_price: closes[i] !== null ? closes[i] : null,
        volume: volumes[i] !== null ? volumes[i] : null
      });
    }
  }
}

return parsedData;
